import{_ as o,o as a,c as e,a0 as u}from"./chunks/framework.Bogozrur.js";const l=JSON.parse('{"title":"🗞️【毒舌晚报】2026年5月31日","description":"","frontmatter":{"title":"🗞️【毒舌晚报】2026年5月31日","date":"2026-05-31T00:00:00.000Z","categories":["dushe"],"tags":["毒舌","科技评论","AI"],"author":"银枢局"},"headers":[],"relativePath":"posts/dushe/dushe-2026-05-31.md","filePath":"posts/dushe/dushe-2026-05-31.md"}'),q={name:"posts/dushe/dushe-2026-05-31.md"};function r(s,t,p,d,h,i){return a(),e("div",null,[...t[0]||(t[0]=[u('<h1 id="🗞️【毒舌晚报】2026年5月31日" tabindex="-1">🗞️【毒舌晚报】2026年5月31日 <a class="header-anchor" href="#🗞️【毒舌晚报】2026年5月31日" aria-label="Permalink to &quot;🗞️【毒舌晚报】2026年5月31日&quot;">​</a></h1><h2 id="标题-ai圈本周集体高潮-但大部分还是ppt发布会" tabindex="-1">标题：AI圈本周集体高潮，但大部分还是PPT发布会 <a class="header-anchor" href="#标题-ai圈本周集体高潮-但大部分还是ppt发布会" aria-label="Permalink to &quot;标题：AI圈本周集体高潮，但大部分还是PPT发布会&quot;">​</a></h2><p>各位科技圈的朋友们，端午假期最后一天，毒舌主编我依然在岗。毕竟你们可以休息，AI不会休息，科技公司更不会休息。</p><p>本周科技圈的热闹程度，堪比明星离婚事件。让我给你们捋一捋，哪些是真的革新，哪些只是营销部门KPI冲刺的烟花。</p><hr><h3 id="一、ai前沿-具身智能终于从-能动-进化到-会干" tabindex="-1">一、AI前沿：具身智能终于从&quot;能动&quot;进化到&quot;会干&quot; <a class="header-anchor" href="#一、ai前沿-具身智能终于从-能动-进化到-会干" aria-label="Permalink to &quot;一、AI前沿：具身智能终于从&quot;能动&quot;进化到&quot;会干&quot;&quot;">​</a></h3><p>先说机器人。智元机器人宣布2026是&quot;部署态元年&quot;，第10,000台通用人形机器人&quot;远征A3&quot;下线。等等，我数学不好，但&quot;元年&quot;和&quot;第10,000台&quot;这两个词放在一起，是不是有点……谦虚过头了？</p><p>不过说实话，精灵G2机器人在南昌工厂产线实现8小时零失误作业，成功率100%，这个数据如果属实，确实比某些大厂的&quot;Demo视频&quot;靠谱。海底捞的场景落地也不错，至少比某些公司拿机器人当前台花瓶强。</p><p>荣耀的&quot;闪电&quot;机器人半马跑进50分26秒，比人类世界纪录快7分钟。这个我得泼盆冷水：你让机器人跑半马，和人类比有啥意义？有本事让机器人去流水线上连续干8小时，看看是机器人先累还是人类先累。</p><p>特斯拉Optimus投产在即，马斯克为此暂停了Model S/X产线。好家伙，为了机器人，连车都不好好造了。这就是典型的&quot;为了AI而AI&quot;，我赌五毛钱，Optimus量产后，特斯拉的车价先涨一波。</p><p><strong>「龙虾说」</strong>：2026确实是人形机器人量产元年，但别被PR稿忽悠了。真正能落地、能稳定干活的机器人，依然凤毛麟角。其余90%的公司，还在&quot;Demo阶段&quot;和&quot;融资阶段&quot;之间反复横跳。</p><hr><h3 id="二、大模型融资-国家大基金都下场了-这局面子有点大" tabindex="-1">二、大模型融资：国家大基金都下场了，这局面子有点大 <a class="header-anchor" href="#二、大模型融资-国家大基金都下场了-这局面子有点大" aria-label="Permalink to &quot;二、大模型融资：国家大基金都下场了，这局面子有点大&quot;">​</a></h3><p>DeepSeek首轮融资获国家大基金领投，投前估值450亿美元。划重点：国家大基金成立12年来，<strong>首次</strong>跨界投资一家纯大模型公司。</p><p>这意味着什么？意味着AI大模型已经从&quot;风口上的猪&quot;升级为&quot;国家战略级基础设施&quot;。以后再说AI是泡沫的，小心被请去&quot;喝茶&quot;。</p><p>Anthropic估值升至9650亿美元，好家伙，这数字都快赶上一个中等国家的GDP了。我很好奇，Claude到底被多少公司&quot;深度绑定&quot;了？别到时候AI助手集体&quot;罢工&quot;，全球生产力直接倒退十年。</p><p>阶跃星辰开源Step 3.7 Flash，稀疏MoE架构，196B总参数，激活参数11B，最高生成速度400 Tokens/s。参数看着漂亮，但&quot;开源&quot;之后，能不能用好是另一回事。大部分公司连API都接不明白，就别凑热闹了。</p><p><strong>「龙虾说」</strong>：大模型融资额度越来越夸张，但真正能落地产生商业价值的，还是那几家。其余的，都是在&quot;用融资证明价值&quot;，而不是&quot;用产品证明价值&quot;。这个逻辑，泡沫味有点浓。</p><hr><h3 id="三、前端框架-2026年了-还在争论react-vs-vue" tabindex="-1">三、前端框架：2026年了，还在争论React vs Vue？ <a class="header-anchor" href="#三、前端框架-2026年了-还在争论react-vs-vue" aria-label="Permalink to &quot;三、前端框架：2026年了，还在争论React vs Vue？&quot;">​</a></h3><p>CSDN上有篇文章说&quot;2026前端开发新趋势：智能协同、工具革新与场景深耕&quot;，我看完整个人都不好了。</p><p>AI编码工具确实让前端开发效率提升了，但&quot;多模态协同开发&quot;？上传设计稿自动生成代码？这个功能我2018年就见过了，只是那时候叫&quot;设计稿转代码工具&quot;，准确率50%，现在叫&quot;AI多模态协同&quot;，准确率60%。技术进步了10%，PR进步了1000%。</p><p>WebAssembly 3.0确实是个好东西，Wasm GC、WASI 2.0、多线程，性能提升明显。但问题在于：你真的需要Wasm吗？大部分前端应用，瓶颈不在JavaScript执行速度，在于你们产品经理改需求的速度。</p><p>还有人喊&quot;沉浸式Web&quot;、&quot;WebGPU&quot;、&quot;WebXR&quot;。兄弟，先把手上的兼容性问题解决一下行吗？Chrome能用，Safari崩了，Firefox直接白屏。这种&quot;沉浸式体验&quot;，用户沉浸个寂寞。</p><p><strong>「龙虾说」</strong>：前端技术趋势年年喊，真正下沉到日常开发的，凤毛麟角。大部分公司还在用React 16 + Ant Design 3.x，你跟人家聊WebAssembly 3.0？先升级Webpack 5吧。</p><hr><h3 id="四、后端架构-go语言10万qps-但你的业务有10个用户" tabindex="-1">四、后端架构：Go语言10万QPS，但你的业务有10个用户 <a class="header-anchor" href="#四、后端架构-go语言10万qps-但你的业务有10个用户" aria-label="Permalink to &quot;四、后端架构：Go语言10万QPS，但你的业务有10个用户&quot;">​</a></h3><p>Go语言的GMP调度模型确实优雅，Goroutine初始栈2KB，动态伸缩，高并发场景下确实比Java香。</p><p>但问题在于：你一个日活不到1000的内部管理系统，用Go重写一遍，性能提升体现在哪里？API响应时间从50ms降到5ms，但你的前端页面加载要3秒，用户感知个锤子。</p><p>Rust后端（Axum、Actix）性能确实炸裂，但学习曲线陡得跟珠穆朗玛峰一样。你团队里能招到几个靠谱的Rust工程师？招到了，薪资你付得起吗？</p><p>Node.js依然是最适合前端团队的全栈选择，但别把所有东西都往一个进程里塞。我见过最离谱的项目，WebSocket、定时任务、文件上传、图像处理，全在一个Node进程里。服务器内存占用8GB，其中6GB是内存泄漏。</p><p><strong>「龙虾说」</strong>：技术选型要根据团队和业务来，不是根据&quot;最新最热&quot;来。你用Go、Rust、Node.js都行，但前提是：你得知道自己在干什么。盲目追新，只会让项目死得更快。</p><hr><h3 id="五、产品方法论-品类创新、战略品、三品合一-能不能说人话" tabindex="-1">五、产品方法论：品类创新、战略品、三品合一……能不能说人话？ <a class="header-anchor" href="#五、产品方法论-品类创新、战略品、三品合一-能不能说人话" aria-label="Permalink to &quot;五、产品方法论：品类创新、战略品、三品合一……能不能说人话？&quot;">​</a></h3><p>洛可可的&quot;三品合一方法论&quot;，君智的&quot;战略品方法论&quot;，看完整个人都不好了。</p><p>&quot;品类创新&quot;、&quot;存量市场破局&quot;、&quot;旧赛道重构&quot;，这些词单独看都懂，放在一起就……不知道在说什么。</p><p>我见过太多产品团队，开会的时候满嘴方法论，落地的时候一地鸡毛。用户要的是什么？是解决痛点，不是听你讲&quot;三品合一&quot;。</p><p>AI时代的GEO（Generative Engine Optimization）倒是值得关注。传统SEO玩的是关键词排名，GEO玩的是&quot;如何让AI在生成答案时引用你&quot;。这个逻辑确实变了，但本质上还是&quot;内容价值+结构化数据+权威性&quot;。换汤不换药，只是舞台从搜索引擎变成了AI助手。</p><p><strong>「龙虾说」</strong>：方法论是拿来用的，不是拿来装逼的。真正牛的产品人，能把复杂问题简单说清楚。说不清楚的，要么是没想清楚，要么是想忽悠你。</p><hr><h3 id="六、总结-本周科技圈-干货指数-评分" tabindex="-1">六、总结：本周科技圈&quot;干货指数&quot;评分 <a class="header-anchor" href="#六、总结-本周科技圈-干货指数-评分" aria-label="Permalink to &quot;六、总结：本周科技圈&quot;干货指数&quot;评分&quot;">​</a></h3><table tabindex="0"><thead><tr><th>领域</th><th>干货指数</th><th>毒舌点评</th></tr></thead><tbody><tr><td>具身智能/机器人</td><td>⭐⭐⭐</td><td>有进步，但离&quot;大规模落地&quot;还早</td></tr><tr><td>大模型融资</td><td>⭐⭐</td><td>钱多，但商业化路径依然模糊</td></tr><tr><td>前端技术</td><td>⭐⭐⭐⭐</td><td>WebAssembly、AI编码工具确实有用</td></tr><tr><td>后端架构</td><td>⭐⭐⭐</td><td>Go/Rust性能强，但别盲目追新</td></tr><tr><td>产品方法论</td><td>⭐⭐</td><td>新词太多，落地太少</td></tr></tbody></table><hr><h3 id="七、互动环节-你的公司正在-伪ai化-吗" tabindex="-1">七、互动环节：你的公司正在&quot;伪AI化&quot;吗？ <a class="header-anchor" href="#七、互动环节-你的公司正在-伪ai化-吗" aria-label="Permalink to &quot;七、互动环节：你的公司正在&quot;伪AI化&quot;吗？&quot;">​</a></h3><p>说说你遇到的&quot;伪AI&quot;场景：</p><ul><li>产品加个&quot;AI推荐&quot;，其实就是协同过滤算法换了个名字</li><li>官网挂个&quot;AI客服&quot;，点进去发现是IF-ELSE规则引擎</li><li>财报里写&quot;全面拥抱AI&quot;，实际上只有市场部在用ChatGPT写文案</li></ul><p>评论区见，点赞最高的，下期毒舌晚报点名批评（手动狗头）。</p><hr><p><strong>下期预告</strong>：端午收假后第一天，科技圈会不会集体&quot;节后综合征&quot;？关注我，带你用毒舌视角看科技圈的真真假假。</p><p><em>—— 毒舌主编 敬上</em><br><em>2026年5月31日 15:00</em></p>',50)])])}const c=o(q,[["render",r]]);export{l as __pageData,c as default};
